/**
 * Transform plugin — applies transformations to arrays of data.
 * 
 * Usage: execute(data, operation)
 * Operations: 'double', 'square', 'negate', 'abs'
 */

const operations = {
  double: (arr) => arr.map(x => x * 2),
  square: (arr) => arr.map(x => x * x),
  negate: (arr) => arr.map(x => -x),
  abs: (arr) => arr.map(x => Math.abs(x)),
};

module.exports = {
  name: 'transform',
  description: 'Apply mathematical transformations to arrays',
  execute(data, operation) {
    if (!Array.isArray(data)) return { error: 'Data must be an array' };
    if (!operations[operation]) return { error: `Unknown operation: ${operation}. Available: ${Object.keys(operations).join(', ')}` };
    return { result: operations[operation](data) };
  },
};

