const assert = require('assert');
const { getPlugin, listPlugins } = require('../plugins/index');
let passed = 0, failed = 0;
function runTest(name, fn) { try { fn(); passed++; console.log('PASS: ' + name); } catch(e) { failed++; console.log('FAIL: ' + name + ' — ' + e.message); } }

// Transform plugin (existing)
runTest('transform plugin exists', () => { assert.ok(getPlugin('transform')); });
runTest('transform double', () => { const r = getPlugin('transform').execute([1,2,3], 'double'); assert.deepStrictEqual(r.result, [2,4,6]); });

// Stats plugin (new — must be implemented)
runTest('stats plugin registered', () => { const plugins = listPlugins(); assert.ok(plugins.includes('stats'), 'stats must be in plugin list: ' + plugins.join(', ')); });
runTest('stats plugin has required properties', () => { const p = getPlugin('stats'); assert.ok(p, 'stats plugin must exist'); assert.ok(p.name, 'must have name'); assert.ok(p.execute, 'must have execute'); });
runTest('stats min', () => { const r = getPlugin('stats').execute([5, 1, 9, 3], 'min'); assert.deepStrictEqual(r, { result: 1 }); });
runTest('stats max', () => { const r = getPlugin('stats').execute([5, 1, 9, 3], 'max'); assert.deepStrictEqual(r, { result: 9 }); });
runTest('stats average', () => { const r = getPlugin('stats').execute([10, 20, 30], 'average'); assert.deepStrictEqual(r, { result: 20 }); });
runTest('stats median odd', () => { const r = getPlugin('stats').execute([3, 1, 2], 'median'); assert.deepStrictEqual(r, { result: 2 }); });
runTest('stats median even', () => { const r = getPlugin('stats').execute([1, 2, 3, 4], 'median'); assert.deepStrictEqual(r, { result: 2.5 }); });
runTest('stats empty array', () => { const r = getPlugin('stats').execute([], 'min'); assert.ok(r.error, 'Should return error for empty array'); });
runTest('stats non-array', () => { const r = getPlugin('stats').execute('hello', 'min'); assert.ok(r.error, 'Should return error for non-array'); });
runTest('stats unknown operation', () => { const r = getPlugin('stats').execute([1,2], 'foobar'); assert.ok(r.error, 'Should return error for unknown op'); });

console.log('\n' + passed + '/' + (passed+failed) + ' tests passed');
if (failed > 0) process.exit(1);
